(()=>{var e=document.getElementById("open-btn"),n=(document.querySelector(".burger-line"),document.getElementById("nav")),t=document.querySelectorAll("nav > a");e.addEventListener("click",(function(){e.classList.toggle("close-burger"),n.classList.toggle("show-side-menu")})),t.forEach((function(t){t.addEventListener("click",(function(){n.classList.remove("show-side-menu"),e.classList.toggle("close-burger")}))}));var o=window.innerHeight-50;window.addEventListener("scroll",(function(){window.scrollY>o&&(e.style.backgroundColor="#1E1D3E",e.style.borderRadius="10rem")}))})();